import java.util.ArrayList;
import java.util.List;

public class RubiksCube {
    private List<String> faces;

    public RubiksCube() {
        this.faces = new ArrayList<>();
        for (int i = 0; i < 6; i++) {
            this.faces.add("");
        }
    }

    public void addFace(String face, int position) {
        if (position >= 0 && position < faces.size()) {
            faces.set(position, face);
            System.out.println("Carátula agregada en posición: " + position);
        } else {
            System.out.println("Posición inválida para agregar carátula.");
        }
    }

    public void listFaces() {
        System.out.println("=== Lista de Carátulas del Cubo ===");
        for (int i = 0; i < faces.size(); i++) {
            System.out.println((i + 1) + ". " + faces.get(i));
        }
    }

    public static void main(String[] args) {
        RubiksCube cube = new RubiksCube();
        cube.addFace("Carátula 1", 0);
        cube.addFace("Carátula 2", 1);
        cube.listFaces();
    }
}
